const express = require('express');
const twilio = require('twilio')(accountSid, authToken);
const session = require('express-session')({
  secret: 'your secret key',
  resave: false,
  saveUninitialized: true,
});

const app = express();
app.use(session);

// Generate random 6-digit codes and send via SMS using Twilio
app.post('/send-code', (req, res) => {
  const code = Math.floor(Math.random() * 1000000).toString().substring(1);
  twilio.messages.create({
    to: req.body.phoneNumber,
    from: 'your Twilio number',
    body: `Your verification code is ${code}.`
  }).then((message) => {
    // Store the code in memory with the user session for validation
    req.session.verificationCode = code;
    res.json({ message: 'Verification code sent successfully' });
  }).catch((err) => {
    console.error(err);
    res.status(500).json({ error: 'Failed to send verification code' });
  });
});

// Verify user input and log in if valid
app.post('/verify-code', (req, res) => {
  const enteredCode = req.body.verificationCode;
  const storedCode = req.session.verificationCode;
  if (enteredCode === storedCode) {
    // Log the user in and redirect to the homepage
    req.session.loggedIn = true;
    res.redirect('/');
  } else {
    res.status(401).json({ error: 'Invalid verification code' });
  }
});